#include <vector>
#include <queue>
#include <climits>
using namespace std;

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    if (n == 0) 
        return -1;

    vector<vector<pair<int, long long>>> graph(n);
    vector<int> in_degree(n, 0);
    long long max_cost = 0;

    for (auto &e : edges) {
        int u = static_cast<int>(e[0]);
        int v = static_cast<int>(e[1]);
        long long cost = e[2];
        graph[u].push_back({v, cost});
        in_degree[v]++;
        if (cost > max_cost) 
            max_cost = cost;
    }

    vector<int> topo_order;
    vector<int> in_deg(in_degree);
    queue<int> q;
    for (int i = 0; i < n; i++) {
        if (in_deg[i] == 0) {
            q.push(i);
        }
    }

    while (!q.empty()) {
        int u = q.front(); 
        q.pop();
        topo_order.push_back(u);
        for (auto &e : graph[u]) {
            int v = e.first;
            if (--in_deg[v] == 0) {
                q.push(v);
            }
        }
    }

    long long low = 0;
    long long high = max_cost;
    long long ans = -1;

    auto check = [&](long long x) -> bool {
        vector<bool> allowed(n, false);
        for (int i = 0; i < n; i++) {
            if (i == 0 || i == n - 1 || online[i])
                allowed[i] = true;
        }

        vector<long long> dp(n, LLONG_MAX / 2);
        dp[0] = 0;

        for (int i = 0; i < topo_order.size(); i++) {
            int u = topo_order[i];
            if (u == n - 1) 
                break;
            if (!allowed[u]) 
                continue;
            for (auto &e : graph[u]) {
                int v = e.first;
                long long cost = e.second;
                if (cost < x) 
                    continue;
                if (!allowed[v]) 
                    continue;
                if (dp[u] + cost < dp[v]) {
                    dp[v] = dp[u] + cost;
                }
            }
        }

        return dp[n - 1] <= k;
    };

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid)) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
}
```

