#include <vector>
#include <queue>
#include <climits>
#include <algorithm>

using namespace std;

bool check(long long mid, const vector<vector<long long>>& base_edges, long long k, int n) {
    vector<vector<pair<int, long long>>> adj(n);
    vector<int> indeg(n, 0);

    for (const auto& e : base_edges) {
        int u = static_cast<int>(e[0]);
        int v = static_cast<int>(e[1]);
        long long cost = e[2];
        if (cost < mid) 
            continue;
        if (v == 0) 
            continue;
        if (u == n-1) 
            continue;
        adj[u].emplace_back(v, cost);
        indeg[v]++;
    }

    vector<long long> dist(n, LLONG_MAX);
    dist[0] = 0;

    queue<int> q;
    for (int i = 0; i < n; i++) {
        if (indeg[i] == 0) {
            q.push(i);
        }
    }

    vector<int> order;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        order.push_back(u);
        for (const auto& edge : adj[u]) {
            int v = edge.first;
            indeg[v]--;
            if (indeg[v] == 0) {
                q.push(v);
            }
        }
    }

    for (int u : order) {
        if (dist[u] == LLONG_MAX) 
            continue;
        for (const auto& edge : adj[u]) {
            int v = edge.first;
            long long w = edge.second;
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
            }
        }
    }

    return dist[n-1] <= k;
}

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<long long>> base_edges;
    for (const auto& e : edges) {
        int u = static_cast<int>(e[0]);
        int v = static_cast<int>(e[1]);
        if (u < 0 || u >= n || v < 0 || v >= n) 
            continue;
        if (online[u] && online[v]) {
            base_edges.push_back(e);
        }
    }

    long long max_edge = 0;
    for (const auto& e : base_edges) {
        if (e[2] > max_edge) {
            max_edge = e[2];
        }
    }

    long long low = 0;
    long long high = max_edge;
    long long ans = -1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, base_edges, k, n)) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
}
